function whos_insert(&$error_message = '') {
	global $Translation;

	// mm: can member insert record?
	$arrPerm = getTablePermissions('whos');
	if(!$arrPerm['insert']) {
		$error_message = $Translation['no insert permission'];
		return false;
	}

	$data = [
		'whos_who1' => Request::val('whos_who1', ''),
		'whos_who2' => Request::val('whos_who2', ''),
		'whos_who3' => Request::val('whos_who3', ''),
		'whos_description' => br2nl(Request::val('whos_description', '')),
		'whos_swg_token' => Request::val('whos_swg_token', ''),
		'whos_swg_email' => br2nl(Request::val('whos_swg_email', '')),
		'whos_premise' => Request::lookup('whos_premise', ''),
		'whos_created' => parseCode('<%%creationTimestamp%%>', true, true),
	];

	// record owner is current user
	$recordOwner = getLoggedMemberID();

	$recID = tableInsert('whos', $data, $recordOwner, $error_message);

	// if this record is a copy of another record, copy children if applicable
	if(strlen(Request::val('SelectedID')) && $recID !== false)
		whos_copy_children($recID, Request::val('SelectedID'));

	return $recID;
}

function whos_copy_children($destination_id, $source_id) {
	global $Translation;
	$requests = []; // array of curl handlers for launching insert requests
	$eo = ['silentErrors' => true];
	$safe_sid = makeSafe($source_id);
	$currentUsername = getLoggedMemberID();
	$errorMessage = '';

	// launch requests, asynchronously
	curl_batch($requests);
}

