function whos_update(&$selected_id, &$error_message = '') {
	global $Translation;

	// mm: can member edit record?
	if(!check_record_permission('whos', $selected_id, 'edit')) return false;

	$data = [
		'whos_who1' => Request::val('whos_who1', ''),
		'whos_who2' => Request::val('whos_who2', ''),
		'whos_who3' => Request::val('whos_who3', ''),
		'whos_description' => br2nl(Request::val('whos_description', '')),
		'whos_swg_token' => Request::val('whos_swg_token', ''),
		'whos_swg_email' => br2nl(Request::val('whos_swg_email', '')),
		'whos_premise' => Request::lookup('whos_premise', ''),
		'whos_updated' => parseCode('<%%editingTimestamp%%>', false, true),
	];

	if($data['whos_who1'] === '') {
		echo StyleSheet() . "\n\n<div class=\"alert alert-danger\">{$Translation['error:']} 'Who1 (Doer Role)': {$Translation['field not null']}<br><br>";
		echo '<a href="" onclick="history.go(-1); return false;">' . $Translation['< back'] . '</a></div>';
		exit;
	}
	if($data['whos_who2'] === '') {
		echo StyleSheet() . "\n\n<div class=\"alert alert-danger\">{$Translation['error:']} 'Who2 (Doer ID)': {$Translation['field not null']}<br><br>";
		echo '<a href="" onclick="history.go(-1); return false;">' . $Translation['< back'] . '</a></div>';
		exit;
	}
	// get existing values
	$old_data = getRecord('whos', $selected_id);
	if(is_array($old_data)) {
		$old_data = array_map('makeSafe', $old_data);
		$old_data['selectedID'] = makeSafe($selected_id);
	}

	$data['selectedID'] = makeSafe($selected_id);

	// hook: whos_before_update
	if(function_exists('whos_before_update')) {
		$args = ['old_data' => $old_data];
		if(!whos_before_update($data, getMemberInfo(), $args)) {
			if(isset($args['error_message'])) $error_message = $args['error_message'];
			return false;
		}
	}

	$set = $data; unset($set['selectedID']);
	foreach ($set as $field => $value) {
		$set[$field] = ($value !== '' && $value !== NULL) ? $value : NULL;
	}

	if(!update(
		'whos',
		backtick_keys_once($set),
		['`whos_id`' => $selected_id],
		$error_message
	)) {
		echo $error_message;
		echo '<a href="whos_view.php?SelectedID=' . urlencode($selected_id) . "\">{$Translation['< back']}</a>";
		exit;
	}


	update_calc_fields('whos', $data['selectedID'], calculated_fields()['whos']);

	// hook: whos_after_update
	if(function_exists('whos_after_update')) {
		if($row = getRecord('whos', $data['selectedID'])) $data = array_map('makeSafe', $row);

		$data['selectedID'] = $data['whos_id'];
		$args = ['old_data' => $old_data];
		if(!whos_after_update($data, getMemberInfo(), $args)) return;
	}

	// mm: update record update timestamp
	set_record_owner('whos', $selected_id);
}

