	if(!$fieldsAreEditable) {
		$jsReadOnly = '';
		$jsReadOnly .= "\t\$j('#whos_who1').replaceWith('<div class=\"form-control-static\" id=\"whos_who1\">' + (\$j('#whos_who1').val() || '') + '</div>');\n";
		$jsReadOnly .= "\t\$j('#whos_who2').replaceWith('<div class=\"form-control-static\" id=\"whos_who2\">' + (\$j('#whos_who2').val() || '') + '</div>');\n";
		$jsReadOnly .= "\t\$j('#whos_who3').replaceWith('<div class=\"form-control-static\" id=\"whos_who3\">' + (\$j('#whos_who3').val() || '') + '</div>');\n";
		$jsReadOnly .= "\t\$j('#whos_description').replaceWith('<div class=\"form-control-static\" id=\"whos_description\">' + (\$j('#whos_description').val() || '') + '</div>');\n";
		$jsReadOnly .= "\t\$j('#whos_swg_token').replaceWith('<div class=\"form-control-static\" id=\"whos_swg_token\">' + (\$j('#whos_swg_token').val() || '') + '</div>');\n";
		$jsReadOnly .= "\t\$j('#whos_swg_email').replaceWith('<div class=\"form-control-static\" id=\"whos_swg_email\">' + (\$j('#whos_swg_email').val() || '') + '</div>');\n";
		$jsReadOnly .= "\t\$j('#whos_premise').prop('disabled', true).css({ color: '#555', backgroundColor: '#fff' });\n";
		$jsReadOnly .= "\t\$j('#whos_premise_caption').prop('disabled', true).css({ color: '#555', backgroundColor: 'white' });\n";
		$jsReadOnly .= "\t\$j('.select2-container').hide();\n";

		$noUploads = true;
	} else {
		// temporarily disable form change handler till time and datetime pickers are enabled
		$jsEditable = "\t\$j('form').eq(0).data('already_changed', true);";
		$jsEditable .= "\t\$j('form').eq(0).data('already_changed', false);"; // re-enable form change handler
	}

	// process combos
	$templateCode = str_replace('<%%COMBO(whos_premise)%%>', $combo_whos_premise->HTML, $templateCode);
	$templateCode = str_replace('<%%COMBOTEXT(whos_premise)%%>', $combo_whos_premise->MatchText, $templateCode);
	$templateCode = str_replace('<%%URLCOMBOTEXT(whos_premise)%%>', urlencode($combo_whos_premise->MatchText), $templateCode);

	/* lookup fields array: 'lookup field name' => ['parent table name', 'lookup field caption'] */
	$lookup_fields = ['whos_premise' => ['premises', 'Whos premise'], ];
	foreach($lookup_fields as $luf => $ptfc) {
		$pt_perm = getTablePermissions($ptfc[0]);

		// process foreign key links
		if(($pt_perm['view'] && isDetailViewEnabled($ptfc[0])) || $pt_perm['edit']) {
			$templateCode = str_replace("<%%PLINK({$luf})%%>", '<button type="button" class="btn btn-default view_parent" id="' . $ptfc[0] . '_view_parent" title="' . html_attr($Translation['View'] . ' ' . $ptfc[1]) . '"><i class="glyphicon glyphicon-eye-open"></i></button>', $templateCode);
		}

		// if user has insert permission to parent table of a lookup field, put an add new button
		if($pt_perm['insert'] /* && !Request::val('Embedded')*/) {
			$templateCode = str_replace("<%%ADDNEW({$ptfc[0]})%%>", '<button type="button" class="btn btn-default add_new_parent" id="' . $ptfc[0] . '_add_new" title="' . html_attr($Translation['Add New'] . ' ' . $ptfc[1]) . '"><i class="glyphicon glyphicon-plus text-success"></i></button>', $templateCode);
		}
	}

	// process images
	$templateCode = str_replace('<%%UPLOADFILE(whos_id)%%>', '', $templateCode);
	$templateCode = str_replace('<%%UPLOADFILE(whos_who1)%%>', '', $templateCode);
	$templateCode = str_replace('<%%UPLOADFILE(whos_who2)%%>', '', $templateCode);
	$templateCode = str_replace('<%%UPLOADFILE(whos_who3)%%>', '', $templateCode);
	$templateCode = str_replace('<%%UPLOADFILE(whos_description)%%>', '', $templateCode);
	$templateCode = str_replace('<%%UPLOADFILE(whos_swg_token)%%>', '', $templateCode);
	$templateCode = str_replace('<%%UPLOADFILE(whos_swg_email)%%>', '', $templateCode);
	$templateCode = str_replace('<%%UPLOADFILE(whos_premise)%%>', '', $templateCode);
	$templateCode = str_replace('<%%UPLOADFILE(whos_created)%%>', '', $templateCode);
	$templateCode = str_replace('<%%UPLOADFILE(whos_updated)%%>', '', $templateCode);

	// process values
	if($hasSelectedId) {
		if( $dvprint) $templateCode = str_replace('<%%VALUE(whos_id)%%>', safe_html($urow['whos_id']), $templateCode);
		if(!$dvprint) $templateCode = str_replace('<%%VALUE(whos_id)%%>', html_attr($row['whos_id']), $templateCode);
		$templateCode = str_replace('<%%URLVALUE(whos_id)%%>', urlencode($urow['whos_id']), $templateCode);
		if( $dvprint) $templateCode = str_replace('<%%VALUE(whos_who1)%%>', safe_html($urow['whos_who1']), $templateCode);
		if(!$dvprint) $templateCode = str_replace('<%%VALUE(whos_who1)%%>', html_attr($row['whos_who1']), $templateCode);
		$templateCode = str_replace('<%%URLVALUE(whos_who1)%%>', urlencode($urow['whos_who1']), $templateCode);
		if( $dvprint) $templateCode = str_replace('<%%VALUE(whos_who2)%%>', safe_html($urow['whos_who2']), $templateCode);
		if(!$dvprint) $templateCode = str_replace('<%%VALUE(whos_who2)%%>', html_attr($row['whos_who2']), $templateCode);
		$templateCode = str_replace('<%%URLVALUE(whos_who2)%%>', urlencode($urow['whos_who2']), $templateCode);
		if( $dvprint) $templateCode = str_replace('<%%VALUE(whos_who3)%%>', safe_html($urow['whos_who3']), $templateCode);
		if(!$dvprint) $templateCode = str_replace('<%%VALUE(whos_who3)%%>', html_attr($row['whos_who3']), $templateCode);
		$templateCode = str_replace('<%%URLVALUE(whos_who3)%%>', urlencode($urow['whos_who3']), $templateCode);
		$templateCode = str_replace('<%%VALUE(whos_description)%%>', safe_html($urow['whos_description'], $fieldsAreEditable), $templateCode);
		$templateCode = str_replace('<%%URLVALUE(whos_description)%%>', urlencode($urow['whos_description']), $templateCode);
		if( $dvprint) $templateCode = str_replace('<%%VALUE(whos_swg_token)%%>', safe_html($urow['whos_swg_token']), $templateCode);
		if(!$dvprint) $templateCode = str_replace('<%%VALUE(whos_swg_token)%%>', html_attr($row['whos_swg_token']), $templateCode);
		$templateCode = str_replace('<%%URLVALUE(whos_swg_token)%%>', urlencode($urow['whos_swg_token']), $templateCode);
		$templateCode = str_replace('<%%VALUE(whos_swg_email)%%>', safe_html($urow['whos_swg_email'], $fieldsAreEditable), $templateCode);
		$templateCode = str_replace('<%%URLVALUE(whos_swg_email)%%>', urlencode($urow['whos_swg_email']), $templateCode);
		if( $dvprint) $templateCode = str_replace('<%%VALUE(whos_premise)%%>', safe_html($urow['whos_premise']), $templateCode);
		if(!$dvprint) $templateCode = str_replace('<%%VALUE(whos_premise)%%>', html_attr($row['whos_premise']), $templateCode);
		$templateCode = str_replace('<%%URLVALUE(whos_premise)%%>', urlencode($urow['whos_premise']), $templateCode);
		$templateCode = str_replace('<%%VALUE(whos_created)%%>', safe_html($urow['whos_created']), $templateCode);
		$templateCode = str_replace('<%%URLVALUE(whos_created)%%>', urlencode($urow['whos_created']), $templateCode);
		$templateCode = str_replace('<%%VALUE(whos_updated)%%>', safe_html($urow['whos_updated']), $templateCode);
		$templateCode = str_replace('<%%URLVALUE(whos_updated)%%>', urlencode($urow['whos_updated']), $templateCode);
	} else {
		$templateCode = str_replace('<%%VALUE(whos_id)%%>', '', $templateCode);
		$templateCode = str_replace('<%%URLVALUE(whos_id)%%>', urlencode(''), $templateCode);
		$templateCode = str_replace('<%%VALUE(whos_who1)%%>', '', $templateCode);
		$templateCode = str_replace('<%%URLVALUE(whos_who1)%%>', urlencode(''), $templateCode);
		$templateCode = str_replace('<%%VALUE(whos_who2)%%>', '', $templateCode);
		$templateCode = str_replace('<%%URLVALUE(whos_who2)%%>', urlencode(''), $templateCode);
		$templateCode = str_replace('<%%VALUE(whos_who3)%%>', '', $templateCode);
		$templateCode = str_replace('<%%URLVALUE(whos_who3)%%>', urlencode(''), $templateCode);
		$templateCode = str_replace('<%%VALUE(whos_description)%%>', '', $templateCode);
		$templateCode = str_replace('<%%URLVALUE(whos_description)%%>', urlencode(''), $templateCode);
		$templateCode = str_replace('<%%VALUE(whos_swg_token)%%>', '', $templateCode);
		$templateCode = str_replace('<%%URLVALUE(whos_swg_token)%%>', urlencode(''), $templateCode);
		$templateCode = str_replace('<%%VALUE(whos_swg_email)%%>', '', $templateCode);
		$templateCode = str_replace('<%%URLVALUE(whos_swg_email)%%>', urlencode(''), $templateCode);
		$templateCode = str_replace('<%%VALUE(whos_premise)%%>', '', $templateCode);
		$templateCode = str_replace('<%%URLVALUE(whos_premise)%%>', urlencode(''), $templateCode);
		$templateCode = str_replace('<%%VALUE(whos_created)%%>', '<%%creationTimestamp%%>', $templateCode);
		$templateCode = str_replace('<%%URLVALUE(whos_created)%%>', urlencode('<%%creationTimestamp%%>'), $templateCode);
		$templateCode = str_replace('<%%VALUE(whos_updated)%%>', '<%%editingTimestamp%%>', $templateCode);
		$templateCode = str_replace('<%%URLVALUE(whos_updated)%%>', urlencode('<%%editingTimestamp%%>'), $templateCode);
	}

	// process translations
	$templateCode = parseTemplate($templateCode);

	// clear scrap
	$templateCode = str_replace('<%%', '<!-- ', $templateCode);
	$templateCode = str_replace('%%>', ' -->', $templateCode);

	// hide links to inaccessible tables
	if(Request::val('dvprint_x') == '') {
		$templateCode .= "\n\n<script>\$j(function() {\n";
		$arrTables = getTableList();
		foreach($arrTables as $name => $caption) {
			$templateCode .= "\t\$j('#{$name}_link').removeClass('hidden');\n";
			$templateCode .= "\t\$j('#xs_{$name}_link').removeClass('hidden');\n";
		}

		$templateCode .= $jsReadOnly;
		$templateCode .= $jsEditable;

		if(!$hasSelectedId) {
		}

		$templateCode.="\n});</script>\n";
	}

	// ajaxed auto-fill fields
	$templateCode .= '<script>';
	$templateCode .= '$j(function() {';


	$templateCode.="});";
	$templateCode.="</script>";
	$templateCode .= $lookups;

	// handle enforced parent values for read-only lookup fields
	$filterField = Request::val('FilterField');
	$filterOperator = Request::val('FilterOperator');
	$filterValue = Request::val('FilterValue');

	// don't include blank images in lightbox gallery
	$templateCode = preg_replace('/blank.gif" data-lightbox=".*?"/', 'blank.gif"', $templateCode);

	// don't display empty email links
	$templateCode=preg_replace('/<a .*?href="mailto:".*?<\/a>/', '', $templateCode);

	/* default field values */
	$rdata = $jdata = get_defaults('whos');
	if($hasSelectedId) {
		$jdata = get_joined_record('whos', $selectedId);
		if($jdata === false) $jdata = get_defaults('whos');
		$rdata = $row;
	}
	$templateCode .= loadView('whos-ajax-cache', ['rdata' => $rdata, 'jdata' => $jdata]);

	// hook: whos_dv
	if(function_exists('whos_dv')) {
		$args = [];
		whos_dv(($hasSelectedId ? $selectedId : FALSE), getMemberInfo(), $templateCode, $args);
	}

	return $templateCode;
}